var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 제 3 방어선! 당장 포격 지원이 필요하다! 당장!!</color>","JPN":"<color=#ffd34c>こちら第3防御船！　直ちに砲撃支援を求む！　今すぐ！！</color>","ENG":"<color=#ffd34c>This is the third line of defense! We need artillery back up! Right now!</color>","TWN":"<color=#ffd34c>這裡是第3防線！請求砲擊支援！立刻！！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>특무함 에이허브! 항해 불능! 비상 착륙 후 지상 방어 거점으로 전환한다!</color>","JPN":"<color=#ffd34c>特務艦エイハブ！　航行不能！　緊急着陸後、地上防御拠点に切り替える！</color>","ENG":"<color=#ffd34c>This is Auxiliary Ship Ahab! We can’t fly anymore! We will perform an emergency landing and switch to ground defense!</color>","TWN":"<color=#ffd34c>特種艦 亞哈！無法行駛！迫降後轉換至地上防禦據點！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님! 적 침식체들이 계속 증원되고 있습니다! 이대로는……!","JPN":"中将！　敵の侵食体が増え続けています！　このままでは……！","ENG":"Lieutenant General! More C.O.s are approaching! At this rate...","TWN":"中將！敵方侵蝕體的數量持續增加中！再這樣下去……！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대체 어디서 이런 괴물들이 나타나는 거지?","JPN":"いったいどこからこの化け物どもが湧いてくるんだ？","ENG":"Where in the world are they coming from?","TWN":"這些怪物到底是從哪冒出來的？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저 녀석이 부상한 좌표에 침식체가 그렇게 많이 집결해 있었나?","JPN":"あいつが浮上した座標に侵食体がここまで大量に集結していたのか？","ENG":"The giant monster brought all these lesser C.O.s with it?","TWN":"那傢伙躍入的座標有聚集麼這麼多侵蝕體嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그건…… 아닌 것 같아.","JPN":"それは……違うみたい。","ENG":"I don’t think so.","TWN":"應該……不是。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"계속 데이터를 확인해 보고 있는데…… 이건 말이 안 돼!","JPN":"ずっとデータを確認してるけど……これはありえないわ！","ENG":"I’ve been looking at the data... and it doesn’t make sense!","TWN":"我一直在看數據……這不太合理！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"왜 그러지, 실비아? 데이터가 어떻길래?","JPN":"どうしたんだ、シルビア？　データは？","ENG":"What is it, Sylvia? What’s wrong with the data?","TWN":"怎麼說，希爾維亞？數據有哪裡不對嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저 괴물이 부상 중인 좌표의 이면세계에는 아무런 반응이 없어.","JPN":"あの化け物が浮上している座標の裏世界には何の反応もないの。","ENG":"I checked the Counterside coordinates where the monster surfaced from.","TWN":"那個怪物躍入中座標的異界沒有任何反應。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정말로, 아무것도 측정이 안 돼,","JPN":"本当に、何も測定できないの。","ENG":"We’re detecting nothing there. I mean, literally nothing.","TWN":"是真的什麼都沒測到。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마…… 이면세계 자체가 붕괴해 버린 건가? 그래서 허수공간이 되어 버렸다고?","JPN":"まさか……裏世界そのものが崩壊してしまったのか？\\nそれで虚数空間になってしまったと？","ENG":"Are you saying that... the Counterside has collapsed and turned into Imaginary Space?","TWN":"難道是……異界自行崩潰嗎？所以才變成虛數空間？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이론상 그렇긴 한데…… 그게 말이 될 리가 없잖아!","JPN":"理論上ではそうだけど……そんなことあり得ないでしょ！","ENG":"Theoretically... yes. But it can’t be!","TWN":"理論上是這樣……但這怎麼可能！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……아니, 가능한 이유가 하나 있지.","JPN":"……いや、その可能性が一つだけある。","ENG":"...Yes, it’s possible. On one condition.","TWN":"……不，是有可能的。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"怎麼說？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"차원 자체에 충격을 줄 수 있을 만큼 거대한 고밀도의 침식파를 가진 존재…….","JPN":"次元自体に衝撃を与えられるほどの強大で高密度な侵食波を持つ存在……","ENG":"A being that radiates a highly dense Corruption Ray... so dense that it could impact the fabric of the dimension itself...","TWN":"那個怪物有可以衝擊次元本身的高密度侵蝕波……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이론 상으로나 존재하긴 하지만…… 그 괴물이라면 그런 일이 가능할지도.","JPN":"理論上でしか存在しないが……あの化け物ならそんなこともできるかもしれない。","ENG":"It was a theory up until now... But with a monster like that, it is possible.","TWN":"雖然只是理論上……但如果是那個怪物，或許有可能。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그건…… 그건 그냥 이론이지! 그냥 수학적으로 지어낸……!","JPN":"あれは……あれはただの理論でしょ！　ただ数学的に作り出した……！","ENG":"But that was just a theory! A mathematical hypothesis!","TWN":"但……那也只是理論而已！只是經過推算的……！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"블랙홀도 처음엔 이론일 뿐이었어, 핑크머리.","JPN":"ブラックホールも最初は理論に過ぎなかったんだ、ピンク頭の嬢ちゃん。","ENG":"Black holes used to be a theory, Pink Hair.","TWN":"黑洞原本也只是個理論而已，粉紅頭！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 관측한 후엔 사실이 되었지.","JPN":"だが、観測された後は事実となった。","ENG":"But they became real when they were actually observed.","TWN":"在經過觀測後就變成事實啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……과연 그렇군.","JPN":"……ああ、そうだな。","ENG":"I see.","TWN":"……果然是這樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아마도 저것이 우리가 처음 관측한 존재.","JPN":"おそらくあれは、我々が初めて観測した存在。","ENG":"So this is the first time we've actually observed...","TWN":"那可能是我們第一次觀測到的存在。"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……제 6종 침식체다.","JPN":"……第6種侵食体だ。","ENG":"The Category 6 Corrupted Object.","TWN":"……6類侵蝕體。"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};